"use strict";(self.webpackChunkclassic=self.webpackChunkclassic||[]).push([[8581],{5610:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Pr\xf3ximo","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Bem-vindo ao ExpressoTS!","href":"/pt/docs/hello","docId":"hello"},{"type":"category","label":"Vis\xe3o geral","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Introdu\xe7\xe3o","href":"/pt/docs/overview/intro","docId":"overview/intro"},{"type":"link","label":"Primeiros Passos","href":"/pt/docs/overview/first-steps","docId":"overview/first-steps"},{"type":"link","label":"Aplica\xe7\xe3o","href":"/pt/docs/overview/application","docId":"overview/application"},{"type":"link","label":"App Container","href":"/pt/docs/overview/app-container","docId":"overview/app-container"},{"type":"link","label":"M\xf3dulos","href":"/pt/docs/overview/module","docId":"overview/module"},{"type":"link","label":"Middleware","href":"/pt/docs/overview/middleware","docId":"overview/middleware"},{"type":"link","label":"Controladores","href":"/pt/docs/overview/controller","docId":"overview/controller"},{"type":"link","label":"Casos de Uso","href":"/pt/docs/overview/usecase","docId":"overview/usecase"},{"type":"link","label":"Provedores","href":"/pt/docs/overview/providers","docId":"overview/providers"},{"type":"link","label":"Reposit\xf3rios","href":"/pt/docs/overview/repositories","docId":"overview/repositories"},{"type":"link","label":"Entidades","href":"/pt/docs/overview/entities","docId":"overview/entities"},{"type":"link","label":"Decoradores","href":"/pt/docs/overview/decorators","docId":"overview/decorators"},{"type":"link","label":"Inje\xe7\xe3o de Depend\xeancias","href":"/pt/docs/overview/di","docId":"overview/di"},{"type":"link","label":"Depend\xeancias","href":"/pt/docs/overview/dependencies","docId":"overview/dependencies"},{"type":"link","label":"C\xf3digo de Status","href":"/pt/docs/overview/status-code","docId":"overview/status-code"},{"type":"link","label":"Gerenciamento de Error","href":"/pt/docs/overview/error-handling","docId":"overview/error-handling"},{"type":"link","label":"Teste","href":"/pt/docs/overview/test","docId":"overview/test"},{"type":"link","label":"Renderizac\xe3o","href":"/pt/docs/overview/render","docId":"overview/render"}],"href":"/pt/docs/category/overview"},{"type":"category","label":"Code By Example","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Bootstrap Method","href":"/pt/docs/codebyexample/bootstrap","docId":"codebyexample/bootstrap"},{"type":"link","label":"Cont\xeainer da Aplica\xe7\xe3o","href":"/pt/docs/codebyexample/app-container","docId":"codebyexample/app-container"},{"type":"link","label":"M\xf3dulos","href":"/pt/docs/codebyexample/modules","docId":"codebyexample/modules"},{"type":"link","label":"Controladores","href":"/pt/docs/codebyexample/controller","docId":"codebyexample/controller"},{"type":"link","label":"Casos de Uso","href":"/pt/docs/codebyexample/usecase","docId":"codebyexample/usecase"},{"type":"link","label":"Entidades","href":"/pt/docs/codebyexample/entities","docId":"codebyexample/entities"},{"type":"link","label":"Utilit\xe1rios ExpressoTS","href":"/pt/docs/codebyexample/utils","docId":"codebyexample/utils"}],"href":"/pt/docs/category/code-by-example"},{"type":"category","label":"CLI","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Vis\xe3o geral","href":"/pt/docs/cli/overview","docId":"cli/overview"},{"type":"link","label":"Gerar recursos","href":"/pt/docs/cli/generate","docId":"cli/generate"}],"href":"/pt/docs/category/cli"},{"type":"category","label":"Providers","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Validador de DTO","href":"/pt/docs/providers/dto-validator","docId":"providers/dto-validator"},{"type":"link","label":"Validator de ambiente","href":"/pt/docs/providers/envvalidator","docId":"providers/envvalidator"},{"type":"link","label":"BD em Mem\xf3ria","href":"/pt/docs/providers/in-memory-db","docId":"providers/in-memory-db"},{"type":"link","label":"Prisma Provider","href":"/pt/docs/providers/prisma","docId":"providers/prisma"}],"href":"/pt/docs/category/providers"},{"type":"link","label":"Roadmap","href":"/pt/docs/roadmap","docId":"roadmap"},{"type":"category","label":"Tutoriais","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Compress\xe3o","href":"/pt/docs/tutorials/compression","docId":"tutorials/compression"},{"type":"link","label":"Cookies","href":"/pt/docs/tutorials/cookies","docId":"tutorials/cookies"}],"href":"/pt/docs/category/tutorials"},{"type":"link","label":"Governan\xe7a","href":"/pt/docs/governance","docId":"governance"}]},"docs":{"cli/generate":{"id":"cli/generate","title":"Gerar recursos","description":"Para proporcionar uma melhor experi\xeancia de desenvolvedor, a CLI do ExpressoTS fornece um conjunto de comandos para ajudar a criar os recursos da aplica\xe7\xe3o, como casos de uso, controladores, DTOs, provedores e servi\xe7os.","sidebar":"tutorialSidebar"},"cli/overview":{"id":"cli/overview","title":"Vis\xe3o geral","description":"O CLI do ExpressoTS \xe9 uma ferramenta de interface de linha de comando que ajuda a criar projetos ExpressoTS e scaffolds de recursos da aplica\xe7\xe3o, como casos de uso, controladores, DTOs, provedores e servi\xe7os.","sidebar":"tutorialSidebar"},"codebyexample/app-container":{"id":"codebyexample/app-container","title":"Cont\xeainer da Aplica\xe7\xe3o","description":"O cont\xeainer da aplica\xe7\xe3o \xe9 um cont\xeainer de inje\xe7\xe3o de depend\xeancias. Veja Cont\xeainer da Aplica\xe7\xe3o para mais informa\xe7\xf5es.","sidebar":"tutorialSidebar"},"codebyexample/bootstrap":{"id":"codebyexample/bootstrap","title":"Bootstrap Method","description":"The bootstrap method is the entry point of your application. It is responsible for loading the application configuration, registering middlewares, and starting the application.","sidebar":"tutorialSidebar"},"codebyexample/controller":{"id":"codebyexample/controller","title":"Controladores","description":"Os controladores s\xe3o respons\xe1veis por manipular solicita\xe7\xf5es recebidas e retornar respostas ao cliente.","sidebar":"tutorialSidebar"},"codebyexample/entities":{"id":"codebyexample/entities","title":"Entidades","description":"Entidades s\xe3o o n\xfacleo da sua aplica\xe7\xe3o. Elas s\xe3o a representa\xe7\xe3o dos seus objetos de neg\xf3cio. Para mais informa\xe7\xf5es sobre entidades, veja Entidades.","sidebar":"tutorialSidebar"},"codebyexample/modules":{"id":"codebyexample/modules","title":"M\xf3dulos","description":"Os m\xf3dulos s\xe3o respons\xe1veis por registrar controladores. Veja M\xf3dulos para mais informa\xe7\xf5es.","sidebar":"tutorialSidebar"},"codebyexample/usecase":{"id":"codebyexample/usecase","title":"Casos de Uso","description":"Casos de uso s\xe3o a implementa\xe7\xe3o da l\xf3gica de neg\xf3cios da sua aplica\xe7\xe3o. Para mais informa\xe7\xf5es sobre casos de uso, veja Casos de Uso.","sidebar":"tutorialSidebar"},"codebyexample/utils":{"id":"codebyexample/utils","title":"Utilit\xe1rios ExpressoTS","description":"C\xf3digos de Status","sidebar":"tutorialSidebar"},"governance":{"id":"governance","title":"Governan\xe7a","description":"ExpressoTS \xe9 constru\xeddo pela sua comunidade. N\xf3s acolhemos e apreciamos contribui\xe7\xf5es de todos os tipos. H\xe1 muitas maneiras de ajudar, desde a reportagem de problemas, a contribui\xe7\xe3o de c\xf3digo e o aux\xedlio para melhorar nossa comunidade.","sidebar":"tutorialSidebar"},"hello":{"id":"hello","title":"Bem-vindo ao ExpressoTS!","description":"ExpressoTS \xe9 projetado para simplificar o processo de desenvolvimento de software, permitindo que os desenvolvedores se concentrem na l\xf3gica de neg\xf3cios principal, abstraindo complexidades t\xe9cnicas. Nosso objetivo \xe9 aumentar sua produtividade por meio de uma estrutura que n\xe3o apenas acelera o desenvolvimento, mas tamb\xe9m oferece documenta\xe7\xe3o abrangente e uma experi\xeancia de desenvolvedor superior, minimizando a necessidade de c\xf3digo gen\xe9rico e repetitivo.","sidebar":"tutorialSidebar"},"overview/app-container":{"id":"overview/app-container","title":"App Container","description":"O ExpressoTS utiliza o InversifyJS para suas capacidades de cont\xeainer de Invers\xe3o de Controle (IoC), fornecendo um sistema robusto para inje\xe7\xe3o de depend\xeancias. Este cont\xeainer consciente de tipos facilita a instancia\xe7\xe3o de objetos, resolu\xe7\xe3o e gest\xe3o de ciclo de vida, possibilitando a cria\xe7\xe3o de depend\xeancias complexas com c\xf3digo m\xednimo.","sidebar":"tutorialSidebar"},"overview/application":{"id":"overview/application","title":"Aplica\xe7\xe3o","description":"No cora\xe7\xe3o de uma aplica\xe7\xe3o ExpressoTS est\xe1 a classe App. Ela serve como a funda\xe7\xe3o para criar e configurar o servidor. Adicionalmente, a classe App permite que middlewares e provedores sejam configurados no processo de inicializa\xe7\xe3o do servidor. A classe App tamb\xe9m oferece hooks (ganchos) de ciclo de vida que permitem aos desenvolvedores executar c\xf3digo antes, depois e durante o desligamento do servidor. Esta se\xe7\xe3o fornece uma vis\xe3o geral da arquitetura da aplica\xe7\xe3o ExpressoTS, seus componentes e o fluxo de trabalho de uma aplica\xe7\xe3o ExpressoTS.","sidebar":"tutorialSidebar"},"overview/controller":{"id":"overview/controller","title":"Controladores","description":"Os Controladores atuam como a principal interface entre o cliente e o servidor em aplica\xe7\xf5es Node.js. Eles lidam com as requisi\xe7\xf5es recebidas, validam os dados conforme o DTO de entrada, e retornam as respostas no formato DTO. Em ess\xeancia, os controllers atuam como a ponte entre os clientes e as camadas de servi\xe7o, tamb\xe9m conhecidas como casos de uso.","sidebar":"tutorialSidebar"},"overview/decorators":{"id":"overview/decorators","title":"Decoradores","description":"Aqui est\xe1 uma lista completa de todos os decoradores que est\xe3o dispon\xedveis no ExpressoTS, bem como uma breve descri\xe7\xe3o do que eles fazem.","sidebar":"tutorialSidebar"},"overview/dependencies":{"id":"overview/dependencies","title":"Depend\xeancias","description":"O prop\xf3sito desta se\xe7\xe3o \xe9 listar todas as depend\xeancias usadas pelo ExpressoTS e nossa vis\xe3o sobre o gerenciamento de depend\xeancias.","sidebar":"tutorialSidebar"},"overview/di":{"id":"overview/di","title":"Inje\xe7\xe3o de Depend\xeancias","description":"Dependency Injection (DI) \xe9 um padr\xe3o de design usado no desenvolvimento de software que envolve fornecer a um objeto as inst\xe2ncias das classes necess\xe1rias para executar suas tarefas, em vez de fazer com que ele mesmo construa essas inst\xe2ncias. Este processo de fornecer inst\xe2ncias \xe9 chamado de injetar nelas, da\xed o termo Inje\xe7\xe3o de Depend\xeancia.","sidebar":"tutorialSidebar"},"overview/entities":{"id":"overview/entities","title":"Entidades","description":"As entidades s\xe3o os componentes principais de uma aplica\xe7\xe3o ExpressoTS. Elas s\xe3o os objetos que s\xe3o usados para representar os dados que ser\xe3o manipulados pela aplica\xe7\xe3o.","sidebar":"tutorialSidebar"},"overview/error-handling":{"id":"overview/error-handling","title":"Gerenciamento de Error","description":"Quando se trata de tratamento de erros nas APIs TypeScript do Node.js, existem v\xe1rias pr\xe1ticas recomendadas e abordagens que voc\xea pode seguir. O ExpressoTS fornece uma maneira simples e f\xe1cil de lidar com erros.","sidebar":"tutorialSidebar"},"overview/first-steps":{"id":"overview/first-steps","title":"Primeiros Passos","description":"Comece sua jornada com o ExpressoTS, um framework TypeScript para construir aplica\xe7\xf5es Node.js escal\xe1veis e mant\xedveis. Esta se\xe7\xe3o orienta voc\xea atrav\xe9s dos conceitos fundamentais, configura\xe7\xe3o e arquitetura do ExpressoTS.","sidebar":"tutorialSidebar"},"overview/intro":{"id":"overview/intro","title":"Introdu\xe7\xe3o","description":"O ExpressoTS oferece uma camada aprimorada sobre o Express.js, enriquecendo o desenvolvimento de aplica\xe7\xf5es TypeScript do lado do servidor. Ele combina a robustez do Express.js com as funcionalidades avan\xe7adas do TypeScript, facilitando a cria\xe7\xe3o de aplica\xe7\xf5es escal\xe1veis, mant\xedveis e leg\xedveis.","sidebar":"tutorialSidebar"},"overview/middleware":{"id":"overview/middleware","title":"Middleware","description":"Fun\xe7\xf5es de middleware s\xe3o fundamentais no ciclo de request-response (solicita\xe7\xe3o-resposta) de uma aplica\xe7\xe3o ExpressoTS, fornecendo a capacidade de executar c\xf3digo, modificar objetos de request-response, encerrar o ciclo de request-response ou chamar o pr\xf3ximo middleware na pilha. \xc9 essencial chamar next() para evitar timeouts de solicita\xe7\xe3o, a menos que seu middleware conclua o ciclo.","sidebar":"tutorialSidebar"},"overview/module":{"id":"overview/module","title":"M\xf3dulos","description":"M\xf3dulos, ou m\xf3dulos de cont\xeainer no ExpressoTS, s\xe3o agrega\xe7\xf5es de servi\xe7os \u2014 principalmente Controladores e suas depend\xeancias \u2014 que s\xe3o gerenciados pelo cont\xeainer do framework. Esses m\xf3dulos facilitam a organiza\xe7\xe3o, registro e resolu\xe7\xe3o de v\xe1rios componentes da aplica\xe7\xe3o dentro do ecossistema ExpressoTS.","sidebar":"tutorialSidebar"},"overview/providers":{"id":"overview/providers","title":"Provedores","description":"No ExpressoTS, provedores servem como melhorias modulares para uma aplica\xe7\xe3o, encapsulando funcionalidades espec\xedficas, como servi\xe7os de email, mecanismos de autentica\xe7\xe3o ou conex\xf5es de banco de dados. Essa encapsula\xe7\xe3o \xe9 essencial para preservar uma arquitetura fracamente acoplada, permitindo a troca ou atualiza\xe7\xe3o dessas funcionalidades sem afetar o sistema geral.","sidebar":"tutorialSidebar"},"overview/render":{"id":"overview/render","title":"Renderizac\xe3o","description":"Express.js oferece um m\xe9todo render para renderizar uma visualiza\xe7\xe3o e enviar a sequ\xeancia HTML renderizada para o cliente.","sidebar":"tutorialSidebar"},"overview/repositories":{"id":"overview/repositories","title":"Reposit\xf3rios","description":"O padr\xe3o de reposit\xf3rio no ExpressoTS fornece uma camada de abstra\xe7\xe3o para o acesso a dados, encapsulando opera\xe7\xf5es CRUD (Criar, Ler, Atualizar, Deletar) dentro de classes de reposit\xf3rio. Esses reposit\xf3rios atuam como intermedi\xe1rios entre a l\xf3gica de neg\xf3cios e as camadas de mapeamento de dados, utilizando ORMs como TypeORM, Prisma ou Sequelize, para interagir com o banco de dados.","sidebar":"tutorialSidebar"},"overview/status-code":{"id":"overview/status-code","title":"C\xf3digo de Status","description":"O c\xf3digo de status \xe9 uma forma de representar o resultado de uma requisi\xe7\xe3o. Essas respostas HTTP indicam se uma solicita\xe7\xe3o HTTP espec\xedfica foi conclu\xedda com \xeaxito. As respostas s\xe3o agrupadas em cinco classes:","sidebar":"tutorialSidebar"},"overview/test":{"id":"overview/test","title":"Teste","description":"Os testes de unidade e os testes de integra\xe7\xe3o s\xe3o importantes em qualquer processo de desenvolvimento de aplicativos porque servem a prop\xf3sitos diferentes.","sidebar":"tutorialSidebar"},"overview/usecase":{"id":"overview/usecase","title":"Casos de Uso","description":"Do ponto de vista da UML, os casos de uso fornecem uma maneira de modelar as intera\xe7\xf5es entre usu\xe1rios, outros sistemas e um aplicativo de software. Um caso de uso descreve um cen\xe1rio espec\xedfico ou fluxo de eventos entre os atores e o sistema, levando a um determinado resultado.","sidebar":"tutorialSidebar"},"providers/dto-validator":{"id":"providers/dto-validator","title":"Validador de DTO","description":"O provedor Validador de DTO \xe9 um recurso que o ExpressoTS oferece nativamente. \xc9 usado para validar os dados vindos do cliente. Ajuda o desenvolvedor a evitar erros em tempo de execu\xe7\xe3o causados por dados faltantes ou inv\xe1lidos.","sidebar":"tutorialSidebar"},"providers/envvalidator":{"id":"providers/envvalidator","title":"Validator de ambiente","description":"O provedor de valida\xe7\xe3o de ambiente \xe9 um provedor que o ExpressoTS oferece por padr\xe3o. Ele \xe9 usado para validar a exist\xeancia do arquivo .env e seu conte\xfado.","sidebar":"tutorialSidebar"},"providers/in-memory-db":{"id":"providers/in-memory-db","title":"BD em Mem\xf3ria","description":"O BD em Mem\xf3ria \xe9 um provedor que usa um banco de dados simples em mem\xf3ria para armazenar dados. \xc9 uma classe injetada no sistema de inje\xe7\xe3o de depend\xeancia do ExpressoTS como um singleton.","sidebar":"tutorialSidebar"},"providers/prisma":{"id":"providers/prisma","title":"Prisma Provider","description":"O Provedor Prisma do ExpressoTS encapsula o robusto ORM (Object-Relational Mapper) Prisma dentro do framework ExpressoTS, criando uma interface transparente para opera\xe7\xf5es de dados. O Prisma facilita um acesso seguro, tipo-seguro e simplificado ao seu banco de dados, garantindo que as intera\xe7\xf5es de dados dentro das suas aplica\xe7\xf5es sejam precisas e eficientes. Seu potente motor de consulta simplifica significativamente o acesso ao banco de dados e mitiga bugs comuns associados \xe0 recupera\xe7\xe3o e manipula\xe7\xe3o de dados.","sidebar":"tutorialSidebar"},"roadmap":{"id":"roadmap","title":"Roadmap","description":"Em breve...","sidebar":"tutorialSidebar"},"tutorials/compression":{"id":"tutorials/compression","title":"Compress\xe3o","description":"O pacote npm compression \xe9 um middleware que pode comprimir corpos de resposta para solicita\xe7\xf5es que passam por ele, o que pode ajudar a reduzir o tamanho dos dados que s\xe3o enviados pela rede, levando a tempos de resposta mais r\xe1pidos e uso menor de largura de banda. Ele usa a biblioteca zlib para realizar a compress\xe3o gzip ou deflate, ambos amplamente suportados pelos navegadores da web modernos.","sidebar":"tutorialSidebar"},"tutorials/cookies":{"id":"tutorials/cookies","title":"Cookies","description":"Cookies s\xe3o pequenos peda\xe7os de dados que um site envia para o navegador da web de um usu\xe1rio enquanto o usu\xe1rio est\xe1 navegando nesse site. Sempre que o usu\xe1rio carrega o site, o navegador envia o cookie de volta ao servidor para notificar o site da atividade anterior do usu\xe1rio.","sidebar":"tutorialSidebar"}}}')}}]);